('6f073787-1e25-4ba7-8b1e-8a36c3287f43', '97b0b299-4f9d-43c8-b7bb-c53028bac5b9', 'new_expire_date date NOT NULL\n  - created_at timestamp NOT NULL\n\nTABLE licenses:\n  - id int NOT NULL\n  - expire_date date NOT NULL\n  - created_at timestamp NOT NULL\n  - updated_at timestamp NOT NULL\n\n\n\nTABLE loan_installment:\n  - loan_inst_id int NOT NULL\n  - employee_id varchar NOT NULL\n  - loan_id varchar NOT NULL\n  - installment_amount varchar NOT NULL\n  - payment varchar NOT NULL\n  - date varchar NOT NULL\n  - received_by varchar NOT NULL\n  - installment_no varchar NOT NULL\n  - notes varchar NOT NULL\n\nTABLE marital_info:\n  - id int NOT NULL\n  - marital_sta varchar NOT NULL\n\nTABLE membership:\n  - id int NOT NULL\n  - membership_name varchar NOT NULL\n  - discount float NOT NULL\n  - other_facilities varchar NOT NULL\n  - create_by int NOT NULL\n  - create_date date NOT NULL\n  - update_by int NOT NULL\n  - update_date date NOT NULL\n  - startpoint int NOT NULL\n  - endpoint int NOT NULL\n\nTABLE menu_add_on:\n  - row_id bigint NOT NULL\n  - menu_id int NOT NULL\n  - add_on_id int NOT NULL\n  - is_active tinyint NOT NULL', 19, 'tauri', '2026-05-25 00:43:20'),
('6f7b4949-ff3b-4784-8f36-46580ee2b2ca', '034d1819-bcd7-487e-91be-db5d0717023a', '(30) → Dashboard, Orders, Products, Delivery, Shops...\n    ├── driver/   (15) → Dashboard, Delivery, Navigation, Wallet, Zones...\n    └── common/   (5)  → Settings, Help, About, Terms, Privacy\n```\n\n\n\n## 🔌 Guide intégration API\n\nChaque fichier `src/data/*.js` → remplacer par appel API :\n\n| Mock file | API endpoint | Méthodes |\n|---|---|---|\n| products.js | `/api/products` | GET POST PUT DELETE |\n| vendors.js | `/api/vendors` | GET |\n| categories.js | `/api/categories` | GET |\n| reviews.js | `/api/products/:id/reviews` | GET POST |\n| vendorData.js | `/api/vendor/*` | GET POST PUT |\n| driverData.js | `/api/driver/*` | GET POST PUT |\n\n### Pattern API recommandé\n```jsx\n// Créer: src/services/api.js\nimport axios from \'axios\';\nexport const api = axios.create({ baseURL: \'https://api.lamuka.cg\' });\n\n// Dans un écran:\nimport { api } from \"../../services/api\";\nconst [products, setProducts] = useState([]);\nuseEffect(() => { api.get(\'/products\').then(r => setProducts(r.data)) }, []);\n```', 2, 'tauri', '2026-05-25 00:43:19');
