('752a73eb-592c-4546-954a-6a15e4564428', '5dd8fc37-3c86-4d1a-b7ab-4235c5585acd', 'lose varchar\n  - maxreserveperson int\n  - printtype int\n\nTABLE shift_assign:\n  - assignid int NOT NULL\n  - shift_id int NOT NULL\n  - emp_his_id int NOT NULL\n  - date date NOT NULL\n  - status tinyint\n\n\n\nTABLE shift_management:\n  - id int NOT NULL\n  - shift_name varchar NOT NULL\n  - start_time time NOT NULL\n  - end_time time NOT NULL\n  - status tinyint NOT NULL\n  - created_at datetime\n\nTABLE shipping_method:\n  - ship_id int NOT NULL\n  - shipping_method varchar NOT NULL\n  - shippingrate decimal NOT NULL\n  - payment_method varchar\n  - is_active int NOT NULL\n  - shiptype int\n\nTABLE sms_configuration:\n  - id int NOT NULL\n  - link text NOT NULL\n  - gateway varchar NOT NULL\n  - user_name varchar NOT NULL\n  - password varchar NOT NULL\n  - sms_from varchar NOT NULL\n  - userid varchar NOT NULL\n  - status int NOT NULL\n\nTABLE sms_template:\n  - id int NOT NULL\n  - template_name varchar NOT NULL\n  - message varchar NOT NULL\n  - type varchar NOT NULL\n  - status tinyint NOT NULL\n  - default_status tinyint NOT NULL\n  - created_at timestamp NOT NULL\n  - updated_at timestamp NOT NULL', 29, 'tauri', '2026-05-25 00:43:19'),
('7598685d-c72b-4209-b06e-2aed5161fa48', '15c81855-2d8a-43a7-85f5-e373a7550619', 'PR #6: Claude/review project m vnwt\nState: closed\nLabels:\n\n## Summary by Sourcery\n\nIntegrate the frontend with new and existing backend APIs for circles, goals, cards, notifications, payments, and support, replacing demo data and local-only state updates with persisted server-driven data flows.\n\nNew Features:\n- Add backend-powered circle chat, membership management, and join/create flows that load and persist data via circlesService.\n- Introduce goal contribution, withdrawal, and deletion capabilities wired to backend goalsService with a reusable contribution modal.\n- Implement virtual card top-up and freeze/unfreeze actions backed by cardService with real balance retrieval.\n- Add full CRUD support for payment methods using a dedicated paymentMethodsService.\n- Introduce paymentsService and supportService to handle contributions and support tickets via backend APIs.\n- Add notificationsService to synchronize notification read state with the server and fetch real notifications.\n- Expose global loading, error, and refreshData handling in AppContext tied to authenticated user data fetching.', 0, 'tauri', '2026-05-25 00:43:19'),
('75b82a1d-7b55-40b2-ae11-12c92499de82', '2b4f13ba-ccb6-418b-ab46-62ee9436c6f5', 'PR #4: feat: Extract all screens from original App.tsx into separate page files\nState: closed\nLabels: \n\n- Created AppContext with all shared state (circles, goals, notifications, transactions, user info, support tickets, security logs, live chat, group chats)\r\n- Updated BottomNavigation to match original design with center elevated Join button\r\n- Updated routes with React Router tab sync and /goals route\r\n- Home.tsx: HomeScreen, NotificationsScreen, WhatsHotScreen\r\n- Circles.tsx: CirclesScreen, JoinScreen, and 21 sub-screens (all create/join flows, group chat, referral, likelemba details, payout methods)\r\n- Wallet.tsx: PaymentsScreen and 10 sub-screens (transaction history, financial dashboard, payment settings, saved cards)\r\n- Card.tsx: CardScreen with virtual card display, freeze/unfreeze, top-up flow, payment method management\r\n- Profile.tsx: ProfileScreen and 16 sub-screens (personal info, documents, security, support, live chat, FAQ)\r\n- Goals.tsx: MyGoalsScreen and 6 sub-screens (goal detail, create goal, saving programs, plan upgrade)\r\n- All original JSX layouts and designs preserved exactly as-is\r\n\r\nhttps://claude.ai/code/session_01DQYEizP5oC7ge3u6Uq7Tpu', 0, 'tauri', '2026-05-25 00:43:19'),
